import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getTutorResponse = async (history: {role: 'user'|'model', parts: {text: string}[]}[], prompt: string) => {
  try {
    const chat = ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: "You are Enara AI, a sophisticated tutor for university and high school students in the MENA region. Your tone is professional, clear, and encouraging. Never be childish. Focus on deep understanding and step-by-step reasoning. Use mathematical notation where appropriate.",
        temperature: 0.7,
      },
    });
    const result = await chat;
    return result.text;
  } catch (error) {
    console.error("AI Response error:", error);
    return "I'm sorry, I'm experiencing a temporary connection issue. How can I help you otherwise?";
  }
};

export const generateAssessment = async (params: any) => {
  const schema = {
    type: Type.OBJECT,
    properties: {
      questions: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            correctIndex: { type: Type.INTEGER },
            explanation: { type: Type.STRING }
          },
          required: ["question", "options", "correctIndex", "explanation"]
        }
      }
    },
    required: ["questions"]
  };

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Generate a ${params.difficulty} difficulty assessment on ${params.topic} with ${params.numQuestions} questions. Learning objectives: ${params.objectives}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: schema
    }
  });

  return JSON.parse(response.text || '{"questions": []}');
};

