  const activeLesson = activeModule.lessons[2];

  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([
    { id: '1', role: 'ai', text: `Hi Sarah! I'm your Enara Learning Assistant. Today we're exploring the **Quadratic Formula**. What part would you like me to clarify for you?`, timestamp: new Date() }
  ]);
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [isReadingId, setIsReadingId] = useState<string | null>(null);

  const chatEndRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMessages, isTyping, isMinimized]);

  const handleSendMessage = async (customText?: string) => {
    const textToSend = customText || inputText;
    if (!textToSend.trim()) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: textToSend, timestamp: new Date() };
    setChatMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsTyping(true);

    const history = chatMessages.map(m => ({
      role: m.role === 'ai' ? 'model' : 'user' as const,
      parts: [{ text: m.text }]
    }));

    const lessonContext = `Subject: ${course.subject}, Module: ${activeModule.title}, Lesson: ${activeLesson.title}`;
