          <div className="flex items-center gap-2 mb-6 text-teal-900 font-bold">
            <List size={18} />
            <span className="text-sm">COURSE OUTLINE</span>
          </div>
          <div className="space-y-1">
            {activeModule.lessons.map((lesson) => (
              <button 
                key={lesson.id} 
                className={`w-full text-left p-3 rounded-xl transition-all flex gap-3 ${
                  lesson.id === activeLesson.id 
                  ? 'bg-teal-50 text-teal-900 border-l-4 border-teal-600' 
                  : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                <span className="text-xs font-bold mt-0.5">{lesson.order}.</span>
                <div>
                  <h6 className="text-sm font-semibold leading-tight">{lesson.title}</h6>
                  <p className="text-[10px] mt-1 flex items-center gap-1 opacity-70">
                    <Clock size={10} /> {lesson.duration}
                  </p>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 space-y-8 overflow-y-auto pb-12">
        <div className="bg-white rounded-3xl p-8 lg:p-12 shadow-sm border border-slate-100">
          <div className="mb-8">
            <div className="flex items-center gap-2 text-slate-400 text-xs font-bold uppercase tracking-widest mb-4">
